package com.example.sharetarget;

import android.content.ClipData;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import java.util.ArrayList;

public class ShareReceiverActivity extends AppCompatActivity {

    private TextView actionView;
    private TextView subjectView;
    private TextView textView;
    private TextView uriListView;
    private ImageView imageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(createContentView());
        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        if (intent == null) {
            showEmptyState();
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        actionView.setText("Action: " + safe(action));
        subjectView.setText("Subject: " + safe(intent.getStringExtra(Intent.EXTRA_SUBJECT)));

        ArrayList<Uri> uris = new ArrayList<>();
        String sharedText = null;

        if (Intent.ACTION_SEND.equals(action)) {
            sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);

            Uri streamUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (streamUri != null) {
                uris.add(streamUri);
            }

            ClipData clipData = intent.getClipData();
            if (clipData != null) {
                for (int i = 0; i < clipData.getItemCount(); i++) {
                    Uri uri = clipData.getItemAt(i).getUri();
                    if (uri != null && !uris.contains(uri)) {
                        uris.add(uri);
                    }
                }
            }
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
            sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);

            ArrayList<Uri> streamUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
            if (streamUris != null) {
                for (Uri uri : streamUris) {
                    if (uri != null && !uris.contains(uri)) {
                        uris.add(uri);
                    }
                }
            }

            ClipData clipData = intent.getClipData();
            if (clipData != null) {
                for (int i = 0; i < clipData.getItemCount(); i++) {
                    Uri uri = clipData.getItemAt(i).getUri();
                    if (uri != null && !uris.contains(uri)) {
                        uris.add(uri);
                    }
                }
            }
        }

        textView.setText("Shared Text:\n" + safe(sharedText));

        if (!uris.isEmpty()) {
            StringBuilder builder = new StringBuilder();
            builder.append("Shared URIs:\n");
            for (Uri uri : uris) {
                builder.append(uri.toString()).append('\n');
            }
            uriListView.setText(builder.toString().trim());

            if (type != null && type.startsWith("image/")) {
                imageView.setImageURI(uris.get(0));
            } else {
                imageView.setImageDrawable(null);
            }
        } else {
            uriListView.setText("Shared URIs:\nNone");
            imageView.setImageDrawable(null);
        }
    }

    private void showEmptyState() {
        actionView.setText("Action: None");
        subjectView.setText("Subject: None");
        textView.setText("Shared Text:\nNone");
        uriListView.setText("Shared URIs:\nNone");
        imageView.setImageDrawable(null);
    }

    private String safe(String value) {
        return TextUtils.isEmpty(value) ? "None" : value;
    }

    private ScrollView createContentView() {
        ScrollView scrollView = new ScrollView(this);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int padding = dp(16);
        root.setPadding(padding, padding, padding, padding);

        actionView = new TextView(this);
        subjectView = new TextView(this);
        textView = new TextView(this);
        uriListView = new TextView(this);
        imageView = new ImageView(this);

        imageView.setAdjustViewBounds(true);

        root.addView(actionView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        root.addView(subjectView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        root.addView(textView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        root.addView(uriListView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        root.addView(imageView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        scrollView.addView(root);
        return scrollView;
    }

    private int dp(int value) {
        return Math.round(value * getResources().getDisplayMetrics().density);
    }
}

